  ('locality-6f0ba476-moex-00171', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-f6c431ec', 'sub-locality-6f0ba476-04', NULL, 'single_choice', '假設僅有甲與乙兩位漁夫沿著一特定海岸捕魚，若沿此海岸建造燈塔，則兩人均可受益。建造額外 一燈塔的邊際成本（MC）為100，額外一燈塔對甲與乙的邊際效益（MB）分別為70-Q與40-Q， 其中Q為燈塔的數量。試求效率的燈塔數量？', '["5", "10", "15", "20"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "b270d478169a", "answer_pdf_sha1": "465f5642fec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1209", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
